class Solution:
    def pacificAtlantic(self, heights):
        m = len(heights)
        n = len(heights[0])
        def can_reach(sr, sc, edge):
            # edge(r,c) True if (r,c) sits on the target ocean border
            seen = [[False] * n for _ in range(m)]
            stack = [(sr, sc)]
            seen[sr][sc] = True
            found = False
            while stack:
                r, c = stack.pop()
                if edge(r, c):
                    found = True
                for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < m and 0 <= nc < n and not seen[nr][nc] and heights[nr][nc] <= heights[r][c]:
                        seen[nr][nc] = True
                        stack.append((nr, nc))
            return found
        pac = lambda r, c: r == 0 or c == 0
        atl = lambda r, c: r == m - 1 or c == n - 1
        res = []
        for r in range(m):
            for c in range(n):
                if can_reach(r, c, pac) and can_reach(r, c, atl):
                    res.append([r, c])
        return res

