class Solution:
    def pacificAtlantic(self, heights):
        m = len(heights)
        n = len(heights[0])
        pac = [[False] * n for _ in range(m)]
        atl = [[False] * n for _ in range(m)]
        def flood(seen, starts):
            stack = list(starts)
            for r, c in starts:
                seen[r][c] = True
            while stack:
                r, c = stack.pop()
                for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < m and 0 <= nc < n and not seen[nr][nc] and heights[nr][nc] >= heights[r][c]:
                        seen[nr][nc] = True
                        stack.append((nr, nc))
        pac_starts = [(r, 0) for r in range(m)] + [(0, c) for c in range(n)]
        atl_starts = [(r, n - 1) for r in range(m)] + [(m - 1, c) for c in range(n)]
        flood(pac, pac_starts)
        flood(atl, atl_starts)
        res = []
        for r in range(m):
            for c in range(n):
                if pac[r][c] and atl[r][c]:
                    res.append([r, c])
        return res

