var pacificAtlantic = function(heights) {
    const m = heights.length, n = heights[0].length;
    const pac = Array.from({length: m}, () => new Array(n).fill(false));
    const atl = Array.from({length: m}, () => new Array(n).fill(false));
    const dirs = [[1, 0], [-1, 0], [0, 1], [0, -1]];
    function flood(seen, starts) {
        const stack = [];
        for (const [r, c] of starts) { seen[r][c] = true; stack.push([r, c]); }
        while (stack.length) {
            const [r, c] = stack.pop();
            for (const [dr, dc] of dirs) {
                const nr = r + dr, nc = c + dc;
                if (nr >= 0 && nr < m && nc >= 0 && nc < n && !seen[nr][nc] && heights[nr][nc] >= heights[r][c]) {
                    seen[nr][nc] = true;
                    stack.push([nr, nc]);
                }
            }
        }
    }
    const pacStarts = [], atlStarts = [];
    for (let r = 0; r < m; r++) { pacStarts.push([r, 0]); atlStarts.push([r, n - 1]); }
    for (let c = 0; c < n; c++) { pacStarts.push([0, c]); atlStarts.push([m - 1, c]); }
    flood(pac, pacStarts);
    flood(atl, atlStarts);
    const res = [];
    for (let r = 0; r < m; r++) {
        for (let c = 0; c < n; c++) {
            if (pac[r][c] && atl[r][c]) res.push([r, c]);
        }
    }
    return res;
};
